import com.example.cleanarchitecture.domain.entity.UserActivity;
import com.example.cleanarchitecture.domain.repository.UserActivityRepository;
import com.example.cleanarchitecture.infrastructure.entity.UserActivityEntity;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.stereotype.Repository;

import java.util.List;
import java.util.stream.Collectors;

@Repository
public class UserActivityRepositoryImpl implements UserActivityRepository {
    private final UserActivityJpaRepository userActivityJpaRepository;

    public UserActivityRepositoryImpl(UserActivityJpaRepository userActivityJpaRepository) {
        this.userActivityJpaRepository = userActivityJpaRepository;
    }

    @Override
    public List<UserActivity> findRecentActivities(int limit) {
        return userActivityJpaRepository.findTopNByOrderByChangedAtDesc(limit)
                .stream()
                .map(this::mapToDomain)
                .collect(Collectors.toList());
    }

    @Override
    public List<UserActivity> findActivitiesByUserId(Long userId, int limit) {
        return userActivityJpaRepository.findTopNByUserIdOrderByChangedAtDesc(userId, limit)
                .stream()
                .map(this::mapToDomain)
                .collect(Collectors.toList());
    }

    @Override
    public UserActivity save(UserActivity activity) {
        UserActivityEntity entity = new UserActivityEntity(
                activity.getUserId(),
                activity.getChangeType(),
                activity.getChangedAt(),
                activity.getChangedBy()
        );
        UserActivityEntity savedEntity = userActivityJpaRepository.save(entity);
        return mapToDomain(savedEntity);
    }

    private UserActivity mapToDomain(UserActivityEntity entity) {
        return new UserActivity(
                entity.getUserId(),
                entity.getChangeType(),
                entity.getChangedAt(),
                entity.getChangedBy()
        );
    }
}

