package com.example.cleanarchitecture.infrastructure.controller;

import com.example.cleanarchitecture.application.dto.ApiResponse;
import com.example.cleanarchitecture.application.service.UserActivityApplicationService;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/users")
public class UserActivityController {
    private final UserActivityApplicationService userActivityApplicationService;

    public UserActivityController(UserActivityApplicationService userActivityApplicationService) {
        this.userActivityApplicationService = userActivityApplicationService;
    }

    @PatchMapping("/{userId}/toggle-status")
    public ResponseEntity<ApiResponse> toggleUserStatus(@PathVariable Long userId) {
        return userActivityApplicationService.toggleUserStatus(userId)
                .map(user -> ResponseEntity.ok(ApiResponse.success(user, "User status toggled successfully")))
                .orElse(ResponseEntity.notFound().build());
    }

    @GetMapping("/activities/recent")
    public ResponseEntity<ApiResponse> getRecentActivities(@RequestParam(defaultValue = "10") int limit) {
        return ResponseEntity.ok(ApiResponse.success(
                userActivityApplicationService.getRecentActivities(limit),
                "Recent activities retrieved successfully"
        ));
    }

    @GetMapping("/{userId}/activities")
    public ResponseEntity<ApiResponse> getUserProfileActivities(
            @PathVariable Long userId,
            @RequestParam(defaultValue = "5") int limit) {
        return ResponseEntity.ok(ApiResponse.success(
                userActivityApplicationService.getUserProfileActivities(userId, limit),
                "User profile activities retrieved successfully"
        ));
    }
}

