package com.example.cleanarchitecture.application.service;

import com.example.cleanarchitecture.application.dto.UserChangeDto;
import com.example.cleanarchitecture.application.dto.UserDTO;
import com.example.cleanarchitecture.domain.entity.User;
import com.example.cleanarchitecture.domain.repository.UserRepository;
import com.example.cleanarchitecture.domain.usecase.CreateUserUseCase;
import com.example.cleanarchitecture.domain.usecase.GetUserUseCase;
import java.time.LocalDateTime;
import java.util.List;
import java.util.Optional;
import java.util.stream.Collectors;

public class UserApplicationService {
    private final CreateUserUseCase createUserUseCase;
    private final GetUserUseCase getUserUseCase;
    private final UserDomainService userDomainService;
    private final UserRepository userRepository;

    public UserApplicationService(
            CreateUserUseCase createUserUseCase,
            GetUserUseCase getUserUseCase,
            UserDomainService userDomainService,
            UserRepository userRepository) {
        this.createUserUseCase = createUserUseCase;
        this.getUserUseCase = getUserUseCase;
        this.userDomainService = userDomainService;
        this.userRepository = userRepository;
    }

    public UserDTO createUser(com.example.cleanarchitecture.application.dto.CreateUserRequest request) {
        User user = createUserUseCase.execute(
            request.getUsername(),
            request.getFirstName(),
            request.getLastName(),
            request.getEmail()
        );
        return new UserDTO(
            user.getId(),
            user.getUsername(),
            user.getFirstName(),
            user.getLastName(),
            user.getEmail(),
            user.getFirstName() + " " + user.getLastName(),
            user.isActive(),
            user.getCreatedAt(),
            user.getUpdatedAt()
        );
    }

    public Optional<UserDTO> getUserById(Long id) {
        return getUserUseCase.execute(id)
            .map(user -> new UserDTO(
                user.getId(),
                user.getUsername(),
                user.getFirstName(),
                user.getLastName(),
                user.getEmail(),
                user.getFirstName() + " " + user.getLastName(),
                user.isActive(),
                user.getCreatedAt(),
                user.getUpdatedAt()
            ));
    }

    public List<UserDTO> getAllActiveUsers() {
        return userDomainService.getActiveUsers().stream()
            .map(user -> new UserDTO(
                user.getId(),
                user.getUsername(),
                user.getFirstName(),
                user.getLastName(),
                user.getEmail(),
                user.getFirstName() + " " + user.getLastName(),
                user.isActive(),
                user.getCreatedAt(),
                user.getUpdatedAt()
            ))
            .collect(Collectors.toList());
    }

    public List<UserDTO> getAllInactiveUsers() {
        return userRepository.findAllInactive().stream()
            .map(user -> new UserDTO(
                user.getId(),
                user.getUsername(),
                user.getFirstName(),
                user.getLastName(),
                user.getEmail(),
                user.getFirstName() + " " + user.getLastName(),
                user.isActive(),
                user.getCreatedAt(),
                user.getUpdatedAt()
            ))
            .collect(Collectors.toList());
    }

    public List<UserChangeDto> getRecentChanges(LocalDateTime since) {
        return userRepository.findByUpdatedAtAfter(since).stream()
            .map(user -> new UserChangeDto(
                user.getId(),
                user.getUsername(),
                user.getFirstName() + " " + user.getLastName(),
                user.isActive(),
                user.getUpdatedAt(),
                "STATUS_UPDATE"
            ))
            .collect(Collectors.toList());
    }

    public void toggleUserStatus(Long userId) {
        Optional<User> userOpt = userRepository.findById(userId);
        userOpt.ifPresent(user -> {
            user.setActive(!user.isActive());
            userRepository.save(user);
        });
    }

    public List<UserChangeDto> getRecentStatusChanges(int limit) {
        LocalDateTime since = LocalDateTime.now().minusDays(7);
        return userRepository.findByUpdatedAtAfter(since).stream()
            .sorted((a, b) -> b.getUpdatedAt().compareTo(a.getUpdatedAt()))
            .limit(limit)
            .map(user -> new UserChangeDto(
                user.getId(),
                user.getUsername(),
                user.getFirstName() + " " + user.getLastName(),
                user.isActive(),
                user.getUpdatedAt(),
                user.isActive() ? "ACTIVATED" : "DEACTIVATED"
            ))
            .collect(Collectors.toList());
    }
}

