package com.example.cleanarchitecture.infrastructure.repository;

import com.example.cleanarchitecture.domain.entity.User;
import com.example.cleanarchitecture.domain.repository.UserRepository;
import com.example.cleanarchitecture.infrastructure.entity.UserEntity;
import jakarta.persistence.EntityManager;
import jakarta.persistence.PersistenceContext;
import jakarta.persistence.TypedQuery;
import java.time.LocalDateTime;
import java.util.List;
import java.util.Optional;
import java.util.stream.Collectors;

public class UserRepositoryImpl implements UserRepository {
    @PersistenceContext
    private EntityManager entityManager;

    public UserRepositoryImpl() {}

    @Override
    public User save(User user) {
        UserEntity entity = new UserEntity(
            user.getId(),
            user.getUsername(),
            user.getFirstName(),
            user.getLastName(),
            user.getEmail(),
            user.isActive(),
            user.getCreatedAt(),
            user.getUpdatedAt()
        );
        entityManager.persist(entity);
        return user;
    }

    @Override
    public List<User> findAll() {
        TypedQuery<UserEntity> query = entityManager.createQuery(
            "SELECT u FROM UserEntity u", UserEntity.class);
        return query.getResultList().stream()
            .map(this::toDomainUser)
            .collect(Collectors.toList());
    }

    @Override
    public List<User> findAllActive() {
        TypedQuery<UserEntity> query = entityManager.createQuery(
            "SELECT u FROM UserEntity u WHERE u.active = true", UserEntity.class);
        return query.getResultList().stream()
            .map(this::toDomainUser)
            .collect(Collectors.toList());
    }

    @Override
    public List<User> findAllInactive() {
        TypedQuery<UserEntity> query = entityManager.createQuery(
            "SELECT u FROM UserEntity u WHERE u.active = false", UserEntity.class);
        return query.getResultList().stream()
            .map(this::toDomainUser)
            .collect(Collectors.toList());
    }

    @Override
    public List<User> findByUpdatedAtAfter(LocalDateTime dateTime) {
        TypedQuery<UserEntity> query = entityManager.createQuery(
            "SELECT u FROM UserEntity u WHERE u.updatedAt > :dateTime", UserEntity.class);
        query.setParameter("dateTime", dateTime);
        return query.getResultList().stream()
            .map(this::toDomainUser)
            .collect(Collectors.toList());
    }

    @Override
    public Optional<User> findById(Long id) {
        UserEntity entity = entityManager.find(UserEntity.class, id);
        return Optional.ofNullable(entity).map(this::toDomainUser);
    }

    @Override
    public Optional<User> findByEmail(String email) {
        TypedQuery<UserEntity> query = entityManager.createQuery(
            "SELECT u FROM UserEntity u WHERE u.email = :email", UserEntity.class);
        query.setParameter("email", email);
        return query.getResultList().stream()
            .findFirst()
            .map(this::toDomainUser);
    }

    @Override
    public Optional<User> findByUsername(String username) {
        TypedQuery<UserEntity> query = entityManager.createQuery(
            "SELECT u FROM UserEntity u WHERE u.username = :username", UserEntity.class);
        query.setParameter("username", username);
        return query.getResultList().stream()
            .findFirst()
            .map(this::toDomainUser);
    }

    @Override
    public boolean existsByEmail(String email) {
        TypedQuery<Long> query = entityManager.createQuery(
            "SELECT COUNT(u) FROM UserEntity u WHERE u.email = :email", Long.class);
        query.setParameter("email", email);
        return query.getSingleResult() > 0;
    }

    @Override
    public boolean existsByUsername(String username) {
        TypedQuery<Long> query = entityManager.createQuery(
            "SELECT COUNT(u) FROM UserEntity u WHERE u.username = :username", Long.class);
        query.setParameter("username", username);
        return query.getSingleResult() > 0;
    }

    @Override
    public void deleteById(Long id) {
        UserEntity entity = entityManager.find(UserEntity.class, id);
        if (entity != null) {
            entityManager.remove(entity);
        }
    }

    @Override
    public long count() {
        TypedQuery<Long> query = entityManager.createQuery(
            "SELECT COUNT(u) FROM UserEntity u", Long.class);
        return query.getSingleResult();
    }

    private User toDomainUser(UserEntity entity) {
        return new User(
            entity.getId(),
            entity.getUsername(),
            entity.getFirstName(),
            entity.getLastName(),
            entity.getEmail(),
            entity.isActive(),
            entity.getCreatedAt(),
            entity.getUpdatedAt()
        );
    }
}

package com.example.cleanarchitecture.infrastructure.controller;

import com.example.cleanarchitecture.application.dto.UserChangeDto;
import com.example.cleanarchitecture.application.dto.UserDTO;
import com.example.cleanarchitecture.application.service.UserApplicationService;
import java.time.LocalDateTime;
import java.util.List;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;

@RestController
@RequestMapping("/api/users")
public class UserController {
    private final UserApplicationService userApplicationService;

    public UserController(UserApplicationService userApplicationService) {
        this.userApplicationService = userApplicationService;
    }

    @GetMapping("/active")
    public ResponseEntity<List<UserDTO>> getAllActiveUsers() {
        return ResponseEntity.ok(userApplicationService.getAllActiveUsers());
    }

    @GetMapping("/inactive")
    public ResponseEntity<List<UserDTO>> getAllInactiveUsers() {
        return ResponseEntity.ok(userApplicationService.getAllInactiveUsers());
    }

    @GetMapping("/recent-changes")
    public ResponseEntity<List<UserChangeDto>> getRecentChanges(
            @RequestParam(required = false, defaultValue = "7") int days) {
        LocalDateTime since = LocalDateTime.now().minusDays(days);
        return ResponseEntity.ok(userApplicationService.getRecentChanges(since));
    }

    @PostMapping("/{userId}/toggle-status")
