package com.example.cleanarchitecture.domain.usecase;

import com.example.cleanarchitecture.domain.entity.User;
import com.example.cleanarchitecture.domain.entity.UserActivityLog;
import com.example.cleanarchitecture.domain.repository.UserActivityLogRepository;
import com.example.cleanarchitecture.domain.repository.UserRepository;
import java.time.LocalDateTime;
import java.util.List;
import java.util.Optional;

public class ToggleUserStatusUseCase {
    private final UserRepository userRepository;
    private final UserActivityLogRepository activityLogRepository;

    public ToggleUserStatusUseCase(UserRepository userRepository, UserActivityLogRepository activityLogRepository) {
        this.userRepository = userRepository;
        this.activityLogRepository = activityLogRepository;
    }

    public User execute(Long userId, boolean newStatus) {
        Optional<User> userOpt = userRepository.findById(userId);
        if (userOpt.isEmpty()) {
            throw new IllegalArgumentException("User not found");
        }

        User user = userOpt.get();
        boolean oldStatus = user.isActive();
        if (oldStatus != newStatus) {
            user.setActive(newStatus);
            user.setUpdatedAt(LocalDateTime.now());

            User savedUser = userRepository.save(user);

            UserActivityLog log = new UserActivityLog();
            log.setUserId(userId);
            log.setAction(newStatus ? "ACTIVATED" : "DEACTIVATED");
            log.setTimestamp(LocalDateTime.now());
            log.setChangedFields("active");
            activityLogRepository.save(log);

            return savedUser;
        }
        return user;
    }
}

