    public UserActivityLogRepositoryImpl(UserActivityLogEntityRepository userActivityLogEntityRepository) {
        this.userActivityLogEntityRepository = userActivityLogEntityRepository;
    }

    @Override
    public UserActivityLog save(UserActivityLog log) {
        UserActivityLogEntity entity = mapToEntity(log);
        UserActivityLogEntity savedEntity = userActivityLogEntityRepository.save(entity);
        return mapToDomain(savedEntity);
    }

    @Override
    public List<UserActivityLog> findRecentByUserId(Long userId, int limit) {
        return userActivityLogEntityRepository.findTopNByUserIdOrderByTimestampDesc(userId, limit)
                .stream()
                .map(this::mapToDomain)
                .collect(Collectors.toList());
    }

    @Override
    public List<UserActivityLog> findRecentGlobal(int limit) {
        return userActivityLogEntityRepository.findTopNByOrderByTimestampDesc(limit)
                .stream()
                .map(this::mapToDomain)
                .collect(Collectors.toList());
    }

    @Override
    public Optional<UserActivityLog> findById(Long id) {
        return userActivityLogEntityRepository.findById(id)
                .map(this::mapToDomain);
    }

    private UserActivityLog mapToDomain(UserActivityLogEntity entity) {
        return new UserActivityLog(
                entity.getId(),
                entity.getUserId(),
                entity.getAction(),
                entity.getTimestamp(),
                entity.getChangedFields()
        );
    }

    private UserActivityLogEntity mapToEntity(UserActivityLog domain) {
        return new UserActivityLogEntity(
                domain.getId(),
                domain.getUserId(),
                domain.getAction(),
                domain.getTimestamp(),
                domain.getChangedFields()
