@Service
public class UserActivityService {
    private final GetUserActivityUseCase getUserActivityUseCase;
    private final GetUsersByStatusUseCase getUsersByStatusUseCase;
    private final ToggleUserStatusUseCase toggleUserStatusUseCase;
    private final GetUserUseCase getUserUseCase;

    public UserActivityService(
            GetUserActivityUseCase getUserActivityUseCase,
            GetUsersByStatusUseCase getUsersByStatusUseCase,
            ToggleUserStatusUseCase toggleUserStatusUseCase,
            GetUserUseCase getUserUseCase) {
        this.getUserActivityUseCase = getUserActivityUseCase;
        this.getUsersByStatusUseCase = getUsersByStatusUseCase;
        this.toggleUserStatusUseCase = toggleUserStatusUseCase;
        this.getUserUseCase = getUserUseCase;
    }

    public List<UserActivityDto> getRecentUserActivities(int limit) {
        return getUserActivityUseCase.executeRecentGlobal(limit).stream()
                .map(this::mapToActivityDto)
                .collect(Collectors.toList());
    }

    public List<UserActivityDto> getUserActivities(Long userId, int limit) {
        return getUserActivityUseCase.executeRecentByUser(userId, limit).stream()
                .map(this::mapToActivityDto)
                .collect(Collectors.toList());
    }

    public List<UserSummaryDto> getUsersByStatus(boolean active) {
        return getUsersByStatusUseCase.execute(active).stream()
                .map(this::mapToSummaryDto)
                .collect(Collectors.toList());
    }

