        return getUserUseCase.execute(log.getUserId())
                .map(user -> new UserActivityDto(
                        log.getId(),
                        log.getUserId(),
                        user.getUsername(),
                        log.getAction(),
                        log.getTimestamp(),
                        log.getChangedFields()
                ))
                .orElse(null);
    }

    private UserSummaryDto mapToSummaryDto(User user) {
        return new UserSummaryDto(
                user.getId(),
                user.getUsername(),
                user.getFirstName() + " " + user.getLastName(),
                user.isActive(),
                user.getUpdatedAt(),
                null
        );
    }
}

