package com.example.cleanarchitecture.infrastructure.controller;

import com.example.cleanarchitecture.application.dto.CreateUserRequest;
import com.example.cleanarchitecture.application.dto.UserDTO;
import com.example.cleanarchitecture.application.service.UserApplicationService;
import jakarta.validation.Valid;
import org.springframework.http.ResponseEntity;
import java.util.regex.Pattern;

public class UserController {
    private final UserApplicationService userApplicationService;

    public UserController(UserApplicationService userApplicationService) {
        this.userApplicationService = userApplicationService;
    }

    public ResponseEntity<UserDTO> createUser(@Valid CreateUserRequest request) {
        if (!isValidEmail(request.getEmail())) {
            throw new IllegalArgumentException("Invalid email format");
        }
        UserDTO userDTO = userApplicationService.createUser(request);
        return ResponseEntity.ok(userDTO);
    }

    public ResponseEntity<UserDTO> getUserById(Long id) {
        return userApplicationService.getUserById(id)
                .map(ResponseEntity::ok)
                .orElseGet(() -> ResponseEntity.notFound().build());
    }

    public ResponseEntity<java.util.List<UserDTO>> getAllActiveUsers() {
        return ResponseEntity.ok(userApplicationService.getAllActiveUsers());
    }

    private boolean isValidEmail(String email) {
        if (email == null || email.isBlank()) {
            return false;
        }
        String emailRegex = "^[A-Za-z0-9+_.-]+@[A-Za-z0-9.-]+$";
        Pattern pattern = Pattern.compile(emailRegex);
        return pattern.matcher(email).matches();
    }
}

