    public ResponseEntity<ApiResponse<UserDTO>> createUser(@Valid CreateUserRequest request) {
        String email = request.getEmail();
        if (email == null || !Pattern.matches("^[A-Za-z0-9+_.-]+@[A-Za-z0-9.-]+$", email)) {
            return ResponseEntity.badRequest()
                    .body(ApiResponse.error("Invalid email format"));
        }
        UserDTO userDTO = userApplicationService.createUser(request);
        return ResponseEntity.status(HttpStatus.CREATED)
                .body(ApiResponse.success(userDTO, "User created successfully"));
    }

    public ResponseEntity<ApiResponse<UserDTO>> getUserById(Long id) {
        return userApplicationService.getUserById(id)
                .map(userDTO -> ResponseEntity.ok(ApiResponse.success(userDTO)))
                .orElseGet(() -> ResponseEntity.notFound().build());
    }

    public ResponseEntity<ApiResponse> getAllActiveUsers() {
        return ResponseEntity.ok(ApiResponse.success(userApplicationService.getAllActiveUsers()));
    }
}

