package com.example.cleanarchitecture.infrastructure.controller;

import com.example.cleanarchitecture.domain.entity.User;
import com.example.cleanarchitecture.domain.repository.UserRepository;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.ResponseBody;

import java.util.List;

class UserExport {
    private final UserRepository userRepository;

    UserExport(UserRepository userRepository) {
        this.userRepository = userRepository;
    }

    @GetMapping("/export/csv")
    @ResponseBody
    public ResponseEntity<String> exportUsersToCsv() {
        List<User> users = userRepository.findAll();
        StringBuilder csv = new StringBuilder();
        csv.append("id,username,firstName,lastName,email,active,createdAt,updatedAt\n");
        for (User user : users) {
            csv.append("%d,%s,%s,%s,%s,%b,%s,%s\n".formatted(
                    user.getId(),
                    escapeCsv(user.getUsername()),
                    escapeCsv(user.getFirstName()),
                    escapeCsv(user.getLastName()),
                    escapeCsv(user.getEmail()),
                    user.isActive(),
                    user.getCreatedAt(),
                    user.getUpdatedAt()
            ));
        }
        return ResponseEntity.ok(csv.toString());
    }

    private String escapeCsv(String value) {
        if (value == null) {
            return "";
        }
        return value.replace("\"", "\"\"").replace("\n", "\\n");
    }
}

package com.example.cleanarchitecture.infrastructure.controller;

import com.example.cleanarchitecture.application.dto.CreateUserRequest;
import com.example.cleanarchitecture.application.dto.UserDTO;
import com.example.cleanarchitecture.application.service.UserApplicationService;
import com.example.cleanarchitecture.shared.ApiResponse;
import jakarta.validation.Valid;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;
import com.example.cleanarchitecture.domain.entity.User;

@RestController
@RequestMapping("/api/users")
public class UserController {
    private final UserApplicationService userApplicationService;

    public UserController(UserApplicationService userApplicationService) {
        this.userApplicationService = userApplicationService;
    }

    @PostMapping
    public ResponseEntity<ApiResponse<UserDTO>> createUser(@Valid @RequestBody CreateUserRequest request) {
        if (request.getEmail() == null || !request.getEmail().matches("^[\\w-.]+@([\\w-]+\\.)+[\\w-]{2,4}$")) {
            throw new IllegalArgumentException("Invalid email format");
        }
        UserDTO userDTO = userApplicationService.createUser(request);
        return ResponseEntity.ok(ApiResponse.success(userDTO, "User created successfully"));
    }

    @PostMapping("/handle")
    public ResponseEntity<ApiResponse> handle(@Valid @RequestBody CreateUserRequest request) {
        if (request.getEmail() == null || !request.getEmail().matches("^[\\w-.]+@([\\w-]+\\.)+[\\w-]{2,4}$")) {
            throw new IllegalArgumentException("Invalid email format");
        }
        UserDTO userDTO = userApplicationService.createUser(request);
        return ResponseEntity.ok(ApiResponse.success(userDTO, "User created successfully"));
    }
}

