        if (request.getEmail() == null || !request.getEmail().matches("^[\\w-.]+@([\\w-]+\\.)+[\\w-]{2,4}$")) {
            throw new IllegalArgumentException("Invalid email format");
        }
        UserDTO userDTO = userApplicationService.createUser(request);
        return ResponseEntity.ok(ApiResponse.success(userDTO, "User created successfully"));
    }

    @PostMapping("/{id}")
    public ResponseEntity<ApiResponse> getUserById(@Valid @RequestBody Long id) {
        return ResponseEntity.ok(ApiResponse.success(userApplicationService.getUserById(id), "User retrieved successfully"));
    }

    @PostMapping("/active")
    public ResponseEntity<ApiResponse> getAllActiveUsers() {
        return ResponseEntity.ok(ApiResponse.success(userApplicationService.getAllActiveUsers(), "Active users retrieved successfully"));
    }
}

