package com.example.cleanarchitecture.infrastructure.repository;

import com.example.cleanarchitecture.domain.entity.User;
import com.example.cleanarchitecture.domain.repository.UserRepository;
import com.example.cleanarchitecture.infrastructure.entity.UserEntity;
import jakarta.persistence.EntityManager;
import jakarta.persistence.PersistenceContext;
import java.util.List;
import java.util.Optional;
import java.util.stream.Collectors;

public class UserRepositoryImpl implements UserRepository {
    @PersistenceContext
    private EntityManager entityManager;

    public UserRepositoryImpl() {
    }

    @Override
    public Optional<User> findById(Long id) {
        return entityManager.find(UserEntity.class, id)
                .map(this::toDomainUser);
    }

    @Override
    public List<User> findAllActive() {
        return entityManager.createQuery(
                        "SELECT u FROM UserEntity u WHERE u.active = true", UserEntity.class)
                .getResultList().stream()
                .map(this::toDomainUser)
                .collect(Collectors.toList());
    }

    @Override
    public boolean existsByUsername(String username) {
        return entityManager.createQuery(
                        "SELECT COUNT(u) > 0 FROM UserEntity u WHERE u.username = :username", Boolean.class)
                .setParameter("username", username)
                .getSingleResult();
    }

    @Override
    public boolean existsByEmail(String email) {
        return entityManager.createQuery(
                        "SELECT COUNT(u) > 0 FROM UserEntity u WHERE u.email = :email", Boolean.class)
                .setParameter("email", email)
                .getSingleResult();
    }

    @Override
    public User save(User user) {
        UserEntity userEntity = toUserEntity(user);
        entityManager.persist(userEntity);
        return toDomainUser(userEntity);
    }

    @Override
    public long count() {
        return entityManager.createQuery("SELECT COUNT(u) FROM UserEntity u", Long.class)
                .getSingleResult();
    }

    @Override
    public Optional<User> findByUsername(String username) {
        return entityManager.createQuery(
                        "SELECT u FROM UserEntity u WHERE u.username = :username", UserEntity.class)
                .setParameter("username", username)
                .getResultStream()
                .findFirst()
                .map(this::toDomainUser);
    }

    @Override
    public void deleteById(Long id) {
        entityManager.createQuery("DELETE FROM UserEntity u WHERE u.id = :id")
                .setParameter("id", id)
                .executeUpdate();
    }

    @Override
    public Optional<User> findByEmail(String email) {
        return entityManager.createQuery(
                        "SELECT u FROM UserEntity u WHERE u.email = :email", UserEntity.class)
                .setParameter("email", email)
                .getResultStream()
                .findFirst()
                .map(this::toDomainUser);
    }

    @Override
    public List<User> findAll() {
        return entityManager.createQuery("SELECT u FROM UserEntity u", UserEntity.class)
                .getResultList().stream()
                .map(this::toDomainUser)
                .collect(Collectors.toList());
    }

    @Override
    public List<User> findByNameOrEmailContaining(String query) {
        String searchPattern = "%" + query.toLowerCase() + "%";
        return entityManager.createQuery(
                        "SELECT u FROM UserEntity u WHERE " +
                                "LOWER(u.firstName) LIKE :query OR " +
                                "LOWER(u.lastName) LIKE :query OR " +
                                "LOWER(u.email) LIKE :query OR " +
                                "LOWER(u.username) LIKE :query", UserEntity.class)
                .setParameter("query", searchPattern)
                .getResultList().stream()
                .map(this::toDomainUser)
                .collect(Collectors.toList());
    }

    private User toDomainUser(UserEntity userEntity) {
        return new User(
                userEntity.getId(),
                userEntity.getUsername(),
                userEntity.getFirstName(),
                userEntity.getLastName(),
                userEntity.getEmail(),
                userEntity.isActive(),
                userEntity.getCreatedAt(),
                userEntity.getUpdatedAt()
        );
    }

    private UserEntity toUserEntity(User user) {
        return new UserEntity(
                user.getId(),
                user.getUsername(),
                user.getFirstName(),
                user.getLastName(),
                user.getEmail(),
                user.isActive(),
                user.getCreatedAt(),
                user.getUpdatedAt()
        );
    }
}

